+// CheckCgroupV2 determines if the host is using cgroup v2 (unified hierarchy).
+func CheckCgroupV2() (bool, error) {
+	data, err := ioutil.ReadFile("/proc/filesystems")
+	if err != nil {
+		return false, fmt.Errorf("cannot read /proc/filesystems: %w", err)
+	}
+	// Look for "cgroup2" entry; if present, cgroup v2 is available
+	for _, line := range strings.Split(string(data), "\n") {
+		if strings.Contains(line, "cgroup2") && !strings.Contains(line, "nodev") {
+			return true, nil
+		}
+	}
+	// Also check if unified mount point exists
+	if _, err := os.Stat("/sys/fs/cgroup/unified"); err == nil {
+		return true, nil
+	}
+	return false, nil
+}
+
+// CheckOverlayWorkspace checks if an overlay filesystem is mounted as the workspace.
+func CheckOverlayWorkspace() (bool, error) {
+	file, err := os.Open("/proc/mounts")
+	if err != nil {
+		return false, fmt.Errorf("cannot open /proc/mounts: %w", err)
+	}
+	defer file.Close()
+
+	scanner := bufio.NewScanner(file)
+	for scanner.Scan() {
+		line := scanner.Text()
+		fields := strings.Fields(line)
+		if len(fields) < 3 {
+			continue
+		}
+		// Match overlay filesystem type (typically "overlay" or "overlay2")
+		if fields[2] == "overlay" || fields[2] == "overlay2" {
+			return true, nil
+		}
+	}
+	return false, scanner.Err()
+}
+
+// CheckSchedulerEvidence verifies that CPU scheduling constraints are present via cgroup.
+func CheckSchedulerEvidence() (bool, error) {
+	// Check for cpu controller in cgroup (either v1 or v2)
+	cpuFiles := []string{
+		"/sys/fs/cgroup/cpu/cpu.cfs_quota_us",
+		"/sys/fs/cgroup/cpu.max", // cgroup v2
+	}
+	for _, f := range cpuFiles {
+		if _, err := os.Stat(f); err == nil {
+			// Also read to confirm it's set (non-zero, non-max)
+			data, _ := ioutil.ReadFile(f)
+			content := strings.TrimSpace(string(data))
+			if content != "" && content != "max" && content != "-1" {
+				return true, nil
+			}
+		}
+	}
+	// Additionally, check common env vars that hint at container limits
+	if os.Getenv("CPU_QUOTA") != "" || os.Getenv("DOCKER_CPU_QUOTA") != "" {
+		return true, nil
+	}
+	return false, nil
+}
+
+// CheckCleanupEvidence checks that temporary workspaces are properly removed.
+func CheckCleanupEvidence() (bool, error) {
+	tmpDir := os.TempDir()
+	// Look for leftover review workspace directories (prefix "review-ws-")
+	dirs, err := ioutil.ReadDir(tmpDir)
+	if err != nil {
+		return false, fmt.Errorf("cannot list temp dir: %w", err)
+	}
+	for _, d := range dirs {
+		if d.IsDir() && strings.HasPrefix(d.Name(), "review-ws-") {
+			// Found leftover; return false meaning cleanup evidence indicates failure
+			return false, nil
+		}
+	}
+	return true, nil
+}
+
 // CollectResourceIsolationEvidence produces evidence by inspecting the environment.
 func CollectResourceIsolationEvidence() (*ResourceIsolationEvidence, error) {
-	evidence := &ResourceIsolationEvidence{}
+	evidence := &ResourceIsolationEvidence{
+		CgroupV2:       false,
+		OverlayPresent: false,
+		Scheduler:      false,
+		Cleanup:        false,
+	}

-	// TODO: Implement real evidence collection (cgroup v2, overlay, scheduler, cleanup)
-	// This is a placeholder.
-	evidence.CgroupV2 = true
-	evidence.OverlayPresent = true
-	evidence.Scheduler = true
-	evidence.Cleanup = true
+	var err error
+	evidence.CgroupV2, err = CheckCgroupV2()
+	if err != nil {
+		return nil, fmt.Errorf("cgroup v2 check: %w", err)
+	}
+	evidence.OverlayPresent, err = CheckOverlayWorkspace()
+	if err != nil {
+		return nil, fmt.Errorf("overlay workspace check: %w", err)
+	}
+	evidence.Scheduler, err = CheckSchedulerEvidence()
+	if err != nil {
+		return nil, fmt.Errorf("scheduler evidence check: %w", err)
+	}
+	evidence.Cleanup, err = CheckCleanupEvidence()
+	if err != nil {
+		return nil, fmt.Errorf("cleanup evidence check: %w", err)
+	}

+	// Attempt to detect container runtime (simple heuristic)
+	evidence.ContainerRuntime = detectContainerRuntime()

 	return evidence, nil
 }
+
+// detectContainerRuntime tries to guess the container runtime from cgroup info.
+func detectContainerRuntime() string {
+	if _, err := os.Stat("/run/.containerenv"); err == nil {
+		return "podman"
+	}
+	if _, err := os.Stat("/.dockerenv"); err == nil {
+		return "docker"
+	}
+	data, _ := ioutil.ReadFile("/proc/1/cgroup")
+	if strings.Contains(string(data), "docker") {
+		return "docker"
+	}
+	if strings.Contains(string(data), "podman") {
+		return "podman"
+	}
+	if strings.Contains(string(data), "lxc") {
+		return "lxc"
+	}
+	return "unknown"
+}
