+package review
+
+import (
+	"os"
+	"path/filepath"
+	"testing"
+)
+
+// TestCheckCgroupV2 verifies the cgroup v2 detection logic.
+func TestCheckCgroupV2(t *testing.T) {
+	result, err := CheckCgroupV2()
+	if err != nil {
+		t.Fatalf("CheckCgroupV2 returned error: %v", err)
+	}
+	// In a test environment (CI) cgroup2 may or may not be present; just check it runs
+	t.Logf("CgroupV2: %v", result)
+}
+
+// TestCheckOverlayWorkspace verifies overlay detection.
+func TestCheckOverlayWorkspace(t *testing.T) {
+	result, err := CheckOverlayWorkspace()
+	if err != nil {
+		t.Fatalf("CheckOverlayWorkspace returned error: %v", err)
+	}
+	t.Logf("OverlayWorkspace: %v", result)
+}
+
+// TestCheckSchedulerEvidence verifies scheduler evidence detection.
+func TestCheckSchedulerEvidence(t *testing.T) {
+	result, err := CheckSchedulerEvidence()
+	if err != nil {
+		t.Fatalf("CheckSchedulerEvidence returned error: %v", err)
+	}
+	t.Logf("Scheduler: %v", result)
+}
+
+// TestCheckCleanupEvidence verifies cleanup evidence detection.
+func TestCheckCleanupEvidence(t *testing.T) {
+	// Create a temporary directory mimicking a left-over workspace
+	tmpDir := os.TempDir()
+	leftoverDir := filepath.Join(tmpDir, "review-ws-testleftover")
+	os.MkdirAll(leftoverDir, 0755)
+	defer os.RemoveAll(leftoverDir)
+
+	// First, check when leftover exists
+	result, err := CheckCleanupEvidence()
+	if err != nil {
+		t.Fatalf("CheckCleanupEvidence with leftover returned error: %v", err)
+	}
+	if result != false {
+		t.Errorf("Expected false (cleanup failure) when leftover directory present, got %v", result)
+	}
+
+	// Remove leftover and verify cleanup passes
+	os.RemoveAll(leftoverDir)
+	result, err = CheckCleanupEvidence()
+	if err != nil {
+		t.Fatalf("CheckCleanupEvidence after cleanup returned error: %v", err)
+	}
+	if result != true {
+		t.Errorf("Expected true (cleanup success) after removing leftover, got %v", result)
+	}
+}
+
+// TestCollectResourceIsolationEvidence ensures the collector runs without error.
+func TestCollectResourceIsolationEvidence(t *testing.T) {
+	evidence, err := CollectResourceIsolationEvidence()
+	if err != nil {
+		t.Fatalf("CollectResourceIsolationEvidence returned error: %v", err)
+	}
+	if evidence == nil {
+		t.Fatal("CollectResourceIsolationEvidence returned nil evidence")
+	}
+	t.Logf("Evidence: %+v", evidence)
+}
